    // weight: [Cout,Cin,Kw,Kh,Kd]
    const gert::Shape *wShape = context->GetInputShape(1);
    const auto cout = static_cast<uint32_t>(wShape->GetDim(0));
    const auto cin  = static_cast<uint32_t>(wShape->GetDim(1));
    const auto kw   = static_cast<uint32_t>(wShape->GetDim(2));
    const auto kh   = static_cast<uint32_t>(wShape->GetDim(3));
    const auto kd   = static_cast<uint32_t>(wShape->GetDim(4));

    // No padding, stride=1, dilation=1
    const uint32_t wOut = (w >= kw) ? (w - kw + 1) : 0u;
    const uint32_t hOut = (h >= kh) ? (h - kh + 1) : 0u;
    const uint32_t dOut = (d >= kd) ? (d - kd + 1) : 0u;

    // Block strategy: each core handles one (n, cout) pair in a grid-stride loop
    uint32_t pairCount = (n == 0 || cout == 0) ? 1u : (n * cout);
    uint32_t blockDim = pairCount;
    if (blockDim == 0) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;  // conservative for 910B

    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_cin(cin);
    tiling.set_cout(cout);
    tiling.set_w(w);
    tiling.set_h(h);
    tiling.set_d(d);

